import { motion } from "framer-motion";
import { Github, ExternalLink } from "lucide-react";
import Button from "./Button";

export default function ProjectCard({ 
  title, 
  description, 
  tech, 
  features, 
  role, 
  githubLink, 
  demoLink, 
  icon: Icon,
  delay = 0
}) {
  return (
    <motion.div
      className="glass-effect rounded-2xl overflow-hidden border border-white/10 hover:border-primary/30 transition-all duration-300 group flex flex-col h-full"
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.5, delay }}
    >
      {/* Project Image / Icon Placeholder */}
      <div className="h-48 w-full bg-gradient-to-br from-primary/20 to-secondary relative flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 bg-black/20 group-hover:bg-transparent transition-colors duration-500 z-10" />
        <Icon size={64} className="text-primary/50 group-hover:scale-110 group-hover:text-primary transition-all duration-500 z-0" />
      </div>

      <div className="p-6 flex flex-col flex-grow">
        <h3 className="text-2xl font-bold mb-2 group-hover:text-primary transition-colors">{title}</h3>
        {role && <p className="text-xs font-semibold text-primary mb-3 uppercase tracking-wider">Role: {role}</p>}
        <p className="text-white/70 mb-6 text-sm flex-grow line-clamp-3 leading-relaxed">{description}</p>

        {/* Features List */}
        {features && features.length > 0 && (
          <div className="mb-6">
            <h4 className="text-sm font-semibold mb-2 text-white/90">Key Features:</h4>
            <ul className="text-xs text-white/60 space-y-1 list-disc list-inside">
              {features.map((feature, idx) => (
                <li key={idx}>{feature}</li>
              ))}
            </ul>
          </div>
        )}

        <div className="flex flex-wrap gap-2 mb-6 mt-auto">
          {tech.map((item, idx) => (
            <span key={idx} className="text-[10px] font-medium px-2 py-1 rounded bg-primary/20 text-primary border border-primary/20 uppercase tracking-widest">
              {item}
            </span>
          ))}
        </div>

        <div className="flex items-center gap-3">
          {githubLink && (
            <a href={githubLink} target="_blank" rel="noopener noreferrer" className="flex-1">
              <Button variant="outline" className="w-full gap-2 text-sm py-2">
                <Github size={16} /> Code
              </Button>
            </a>
          )}
          {demoLink && (
            <a href={demoLink} target="_blank" rel="noopener noreferrer" className="flex-1">
              <Button variant="primary" className="w-full gap-2 text-sm py-2">
                <ExternalLink size={16} /> Live
              </Button>
            </a>
          )}
        </div>
      </div>
    </motion.div>
  );
}

import { motion } from "framer-motion";

export default function SectionHeading({ title, subtitle }) {
  return (
    <div className="text-center mb-12">
      <motion.h2 
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ duration: 0.5 }}
        className="text-3xl md:text-5xl font-bold mb-4"
      >
        {title}
      </motion.h2>
      {subtitle && (
        <motion.p 
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5, delay: 0.1 }}
          className="text-white/60 max-w-2xl mx-auto"
        >
          {subtitle}
        </motion.p>
      )}
      <motion.div 
        initial={{ scaleX: 0 }}
        whileInView={{ scaleX: 1 }}
        viewport={{ once: true }}
        transition={{ duration: 0.5, delay: 0.2 }}
        className="h-1 w-20 bg-primary mx-auto mt-4 rounded-full"
      />
    </div>
  );
}

import { motion } from "framer-motion";
import SectionWrapper from "../components/SectionWrapper";
import SectionHeading from "../components/SectionHeading";
import { Code2, Database, Layout } from "lucide-react";

export default function About() {
  const cards = [
    {
      icon: <Layout className="text-primary mb-4" size={32} />,
      title: "Frontend Engineering",
      desc: "Crafting beautiful, responsive, and intuitive user interfaces using React and modern CSS frameworks like Tailwind."
    },
    {
      icon: <Database className="text-primary mb-4" size={32} />,
      title: "Backend Development",
      desc: "Building scalable APIs, server-side logic, and robust database architectures using Node.js and MongoDB."
    },
    {
      icon: <Code2 className="text-primary mb-4" size={32} />,
      title: "Problem Solving",
      desc: "Applying Data Structures and Algorithms to write efficient code and solve complex logical problems."
    }
  ];

  return (
    <SectionWrapper id="about" className="bg-secondary/20">
      <SectionHeading title="About Me" subtitle="A brief introduction to who I am and what I do." />

      <div className="mt-12 flex flex-col md:flex-row gap-12 items-center">
        {/* Left Side: Summary text */}
        <motion.div 
          className="md:w-1/2"
          initial={{ opacity: 0, x: -30 }}
          whileInView={{ opacity: 1, x: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
        >
          <p className="text-lg leading-relaxed text-white/80 glass-effect p-8 rounded-2xl relative overflow-hidden">
            <span className="absolute top-0 left-0 w-1 h-full bg-primary"></span>
            I am a Computer Science student at <strong className="text-white">Lovely Professional University</strong> with strong skills in full-stack development. 
            I have experience building real-world applications using the <strong className="text-primary">MERN stack</strong> and enjoy solving complex problems using efficient algorithms and clean code.
            My goal is to leverage my skills to build products that deliver exceptional user experiences while maintaining robust and scalable underlying architectures.
          </p>
        </motion.div>

        {/* Right Side: Quick Cards */}
        <div className="md:w-1/2 grid gap-6">
          {cards.map((card, idx) => (
            <motion.div 
              key={idx}
              className="glass-effect p-6 rounded-xl hover:-translate-y-1 transition-transform border border-white/5 hover:border-primary/30"
              initial={{ opacity: 0, x: 30 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5, delay: idx * 0.1 }}
            >
              <div className="flex items-start gap-4">
                <div className="bg-white/5 p-3 rounded-lg border border-white/10">
                  {card.icon}
                </div>
                <div>
                  <h3 className="text-xl font-semibold mb-2">{card.title}</h3>
                  <p className="text-white/60 text-sm leading-relaxed">{card.desc}</p>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </SectionWrapper>
  );
}

import { motion } from "framer-motion";
import SectionWrapper from "../components/SectionWrapper";
import SectionHeading from "../components/SectionHeading";
import { Award, Trophy } from "lucide-react";

export default function Achievements() {
  const achievements = [
    {
      title: "Top 100 in Frontend Hackathon",
      organization: "IIT Bhubaneswar",
      description: "Competed against top developers to build a fully functional frontend application under strict time constraints.",
      icon: <Trophy className="text-yellow-400" size={32} />
    },
    {
      title: "100+ Coding Problems Solved",
      organization: "Various Platforms (LeetCode, HackerRank)",
      description: "Demonstrated strong problem-solving skills and a deep understanding of Data Structures and Algorithms.",
      icon: <Award className="text-primary" size={32} />
    }
  ];

  return (
    <SectionWrapper id="achievements">
      <SectionHeading title="Achievements & Milestones" subtitle="Highlights of my competitive programming and hackathon journey." />

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-12 max-w-5xl mx-auto w-full">
        {achievements.map((item, idx) => (
          <motion.div
            key={idx}
            className="glass-effect p-8 rounded-2xl flex flex-col md:flex-row gap-6 items-center md:items-start text-center md:text-left border border-white/5 hover:border-primary/40 transition-colors"
            initial={{ opacity: 0, scale: 0.95 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.5, delay: idx * 0.2 }}
