            </div>
          </motion.div>
        ))}
      </div>
    </SectionWrapper>
  );
}

import { motion } from "framer-motion";
import SectionWrapper from "../components/SectionWrapper";
import SectionHeading from "../components/SectionHeading";
import { CheckCircle } from "lucide-react";

export default function Certificates() {
  const certificates = [
    { name: "React Certification", issuer: "HackerRank" },
    { name: "Node.js Certification", issuer: "HackerRank" },
    { name: "Generative AI", issuer: "Infosys" },
    { name: "Java Programming", issuer: "NeoColab" }
  ];

  return (
    <SectionWrapper id="certificates" className="bg-secondary/10">
      <SectionHeading title="Certifications" subtitle="Professional credentials validating my technical expertise and continuous learning." />

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mt-12 max-w-7xl mx-auto w-full">
        {certificates.map((cert, idx) => (
          <motion.div
            key={idx}
            className="glass-effect p-6 rounded-xl relative overflow-hidden group cursor-default transition-all duration-300 hover:-translate-y-2 hover:shadow-[0_8px_30px_rgb(59,130,246,0.12)] border border-white/5"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.4, delay: idx * 0.1 }}
          >
            {/* Background Accent */}
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
              <CheckCircle size={64} className="text-primary" />
            </div>

            <div className="relative z-10 flex flex-col h-full justify-between">
              <div>
                <CheckCircle size={28} className="text-primary mb-4" />
                <h3 className="text-lg font-bold mb-2 leading-tight">{cert.name}</h3>
              </div>
              <p className="text-white/50 text-sm font-medium uppercase tracking-wider mt-4">
                {cert.issuer}
              </p>
            </div>

            {/* Hover Glow line */}
            <div className="absolute bottom-0 left-0 h-1 w-0 bg-primary group-hover:w-full transition-all duration-300"></div>
          </motion.div>
        ))}
      </div>
    </SectionWrapper>
  );
}

import { motion } from "framer-motion";
import SectionWrapper from "../components/SectionWrapper";
import SectionHeading from "../components/SectionHeading";
import Button from "../components/Button";
import { Mail, Github, Linkedin, Send } from "lucide-react";

export default function Contact() {
  const contactInfo = [
    {
      icon: <Mail className="text-primary" size={24} />,
      label: "Email",
      value: "ambuj20maurya@gmail.com",
      href: "mailto:ambuj20maurya@gmail.com"
    },
    {
      icon: <Github className="text-primary" size={24} />,
      label: "GitHub",
      value: "github.com/21ambuj",
      href: "https://github.com/21ambuj"
    },
    {
      icon: <Linkedin className="text-primary" size={24} />,
      label: "LinkedIn",
      value: "linkedin.com/in/21ambuj",
      href: "https://linkedin.com/in/21ambuj"
    }
  ];

  return (
    <SectionWrapper id="contact">
      <SectionHeading title="Get In Touch" subtitle="Have a question or want to work together? Let's connect!" />

      <div className="mt-12 flex flex-col lg:flex-row gap-12 w-full max-w-5xl mx-auto">
        {/* Contact Info */}
        <div className="lg:w-1/3 flex flex-col gap-6">
          {contactInfo.map((info, idx) => (
            <motion.a
              key={idx}
              href={info.href}
              target="_blank"
              rel="noopener noreferrer"
              className="glass-effect p-6 rounded-xl flex items-center gap-4 hover:border-primary/50 transition-colors group"
              initial={{ opacity: 0, x: -20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5, delay: idx * 0.1 }}
            >
              <div className="bg-white/5 p-3 rounded-lg group-hover:scale-110 transition-transform">
                {info.icon}
              </div>
              <div>
                <p className="text-sm text-white/50 mb-1">{info.label}</p>
                <p className="text-white font-medium group-hover:text-primary transition-colors">{info.value}</p>
              </div>
            </motion.a>
          ))}
        </div>

        {/* Contact Form */}
        <motion.div 
          className="lg:w-2/3 glass-effect p-8 rounded-2xl"
          initial={{ opacity: 0, x: 20 }}
          whileInView={{ opacity: 1, x: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
        >
          <form className="flex flex-col gap-6" onSubmit={(e) => e.preventDefault()}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="flex flex-col gap-2">
                <label htmlFor="name" className="text-sm text-white/70">Name</label>
                <input 
                  type="text" 
                  id="name"
                  placeholder="John Doe"
                  className="bg-black/20 border border-white/10 rounded-lg px-4 py-3 outline-none focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all text-white placeholder:text-white/20"
                />
              </div>
              <div className="flex flex-col gap-2">
                <label htmlFor="email" className="text-sm text-white/70">Email</label>
                <input 
                  type="email" 
                  id="email"
                  placeholder="john@example.com"
                  className="bg-black/20 border border-white/10 rounded-lg px-4 py-3 outline-none focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all text-white placeholder:text-white/20"
                />
              </div>
            </div>
            <div className="flex flex-col gap-2">
              <label htmlFor="subject" className="text-sm text-white/70">Subject</label>
              <input 
                type="text" 
                id="subject"
                placeholder="Job Opportunity / Freelance Project"
                className="bg-black/20 border border-white/10 rounded-lg px-4 py-3 outline-none focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all text-white placeholder:text-white/20"
              />
            </div>
            <div className="flex flex-col gap-2">
              <label htmlFor="message" className="text-sm text-white/70">Message</label>
              <textarea 
                id="message"
                rows="5"
                placeholder="Hello Ambuj, I'd like to talk about..."
                className="bg-black/20 border border-white/10 rounded-lg px-4 py-3 outline-none focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all text-white placeholder:text-white/20 resize-none"
              ></textarea>
            </div>
            <Button variant="primary" className="gap-2 w-full md:w-auto self-start mt-2">
              Send Message <Send size={18} />
            </Button>
          </form>
        </motion.div>
      </div>
    </SectionWrapper>
  );
}

import { motion } from "framer-motion";
import { Typewriter } from 'react-simple-typewriter';
import { Link } from 'react-scroll';
import SectionWrapper from "../components/SectionWrapper";
import Button from "../components/Button";
import { Download, Rocket } from "lucide-react";

export default function Hero() {
  return (
    <SectionWrapper id="hero" className="pt-32 relative">
      <div className="flex flex-col items-center text-center space-y-8 max-w-4xl mx-auto">

        <motion.div
          initial={{ opacity: 0, scale: 0.8 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.5 }}
          className="inline-block"
        >
          <span className="px-4 py-2 rounded-full border border-white/10 bg-white/5 text-sm font-medium text-primary mb-4 inline-block">
            Available for Internships
          </span>
        </motion.div>

        <motion.h1 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.1 }}
          className="text-5xl md:text-7xl lg:text-8xl font-black leading-tight tracking-tighter"
        >
          Hi, I'm <span className="text-primary">Ambuj</span>
          <br />
          Kumar Maurya
        </motion.h1>

        <motion.h2
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.2 }}
          className="text-2xl md:text-4xl text-white/80 font-semibold h-12"
        >
          <Typewriter
            words={['Full Stack Developer', 'MERN Stack Developer', 'Problem Solver']}
            loop={true}
            cursor
            cursorStyle='_'
            typeSpeed={70}
            deleteSpeed={50}
            delaySpeed={2000}
          />
        </motion.h2>

        <motion.p
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.3 }}
          className="text-lg text-white/60 max-w-2xl"
        >
          Passionate developer building scalable web applications and solving real-world problems.
        </motion.p>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.4 }}
          className="flex flex-col sm:flex-row items-center gap-4"
        >
          <Link to="projects" smooth={true} duration={500} offset={-80}>
            <Button variant="primary" className="gap-2 w-full sm:w-auto">
              View Projects <Rocket size={18} />
            </Button>
          </Link>
          <Button variant="outline" className="gap-2 w-full sm:w-auto hover:bg-white/5 transition-colors">
            Download Resume <Download size={18} />
          </Button>
        </motion.div>

      </div>
    </SectionWrapper>
  );
}

import { motion } from "framer-motion";
import SectionWrapper from "../components/SectionWrapper";
import SectionHeading from "../components/SectionHeading";

export default function Skills() {
  const skillCategories = [
    {
      title: "Languages",
      skills: ["Java", "Python", "JavaScript"]
    },
    {
      title: "Frontend",
      skills: ["React", "HTML", "CSS", "Tailwind CSS"]
    },
    {
      title: "Backend",
      skills: ["Node.js", "Express.js"]
    },
    {
      title: "Database",
      skills: ["MongoDB", "MySQL"]
    },
    {
      title: "Tools",
      skills: ["Git", "GitHub", "VS Code"]
    },
    {
      title: "Soft Skills",
      skills: ["Problem Solving", "Teamwork", "Adaptability"]
